xpath.script:
document.addEventListener('DOMContentLoaded', function () {
    console.log("✅ chatbot inline ativo");

    const toggleButton = document.getElementById('chatbot-toggle-button');
    let chatbotBox = null;
    let typingIndicator = null;
    let inputField = null;
    let messageContainer = null;

    function renderChatbotBox() {
        if (!chatbotBox) {
            chatbotBox = document.createElement("div");
            chatbotBox.id = "chatbot-box";
            chatbotBox.style.cssText = `
                display: none;
                position: fixed;
                bottom: 90px;
                right: 20px;
                width: 350px;
                height: 450px;
                background-color: white;
                border: 1px solid #dcdcdc; /* Borda mais clara */
                border-radius: 10px;
                box-shadow: 0 8px 20px rgba(0,0,0,0.15);
                z-index: 9999;
                flex-direction: column;
                overflow: hidden;
                font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            `;
            chatbotBox.innerHTML = `
                <div id="chatbot-header" style="background-color: #364F3C; color: white; padding: 12px 15px; border-top-left-radius: 9px; border-top-right-radius: 9px; display: flex; justify-content: space-between; align-items: center; font-size: 1.2em; font-weight: bold;">
                    <span>Simbi 🧠</span>
                    <button id="chatbot-inline-close-button" style="background: none; border: none; color: white; font-size: 24px; cursor: pointer;">&#x00D7;</button>
                </div>
                <div id="chatbot-messages-container" style="flex-grow: 1; padding: 15px; overflow-y: auto; background-color: #f8f9fa; /* Fundo levemente cinza */ scroll-behavior: smooth; font-size: 0.95em;"></div>
                <div id="chatbot-typing" style="padding: 8px 15px; font-style: italic; color: #888; text-align: center; display: none; font-size: 0.9em;"><em>digitando...</em></div>
                <div style="padding: 15px; border-top: 1px solid #e9ecef; /* Borda superior mais clara */ display: flex; align-items: center; background-color: #ffffff;">
                    <input type="text" id="chatbot-input" placeholder="Digite sua mensagem..." style="flex-grow: 1; padding: 10px 12px; border: 1px solid #ced4da; /* Borda do input mais clara */ border-radius: 20px; margin-right: 10px; font-size: 1.2em; outline: none; transition: border-color 0.3s ease;"/>
                    <button id="chatbot-send-button" style="background-color: #28a745; /* Verde Bootstrap */ color: white; border: none; padding: 10px 18px; border-radius: 20px; cursor: pointer; font-size: 1.2em; font-weight: bold; transition: background-color 0.3s ease;">Enviar</button>
                </div>
            `;
            document.body.appendChild(chatbotBox);

            typingIndicator = document.getElementById("chatbot-typing");
            inputField = document.getElementById("chatbot-input");
            messageContainer = document.getElementById("chatbot-messages-container");

            const sendButton = document.getElementById("chatbot-send-button");
            const closeButton = document.getElementById("chatbot-inline-close-button");

            inputField.addEventListener("focus", () => {
                inputField.style.borderColor = '#364F3C';
            });
            inputField.addEventListener("blur", () => {
                inputField.style.borderColor = '#ced4da'; /* Voltar para a cor padrão mais clara */
            });

            inputField.addEventListener("keypress", (e) => {
                if (e.key === "Enter") handleInput();
            });
            sendButton.addEventListener("click", handleInput);
            closeButton.addEventListener("click", toggleChatbotVisibility);
        }
    }

    function toggleChatbotVisibility() {
        renderChatbotBox();
        if (chatbotBox.style.display === 'none' || chatbotBox.style.display === '') {
            chatbotBox.style.display = 'flex';
            toggleButton.textContent = '✖️';
            toggleButton.style.backgroundColor = '#dc3545';
        } else {
            chatbotBox.style.display = 'none';
            toggleButton.textContent = '💬';
            toggleButton.style.backgroundColor = '#364F3C';
        }
    }

    function handleInput() {
        const question = inputField.value.trim();
        if (!question) return;

        const userMsg = document.createElement("div");
        userMsg.textContent = question;
        userMsg.style.cssText = `
            margin-bottom: 10px;
            text-align: right;
            background-color: #e3f2fd; /* Azul claro */
            padding: 10px 15px;
            border-radius: 18px 18px 3px 18px;
            max-width: 85%;
            margin-left: auto;
            color: #333;
            box-shadow: 0 1px 2px rgba(0,0,0,0.1);
            word-wrap: break-word;
            font-size: 1em; /* Tamanho da fonte maior para mensagens do usuário */
        `;
        messageContainer.appendChild(userMsg);

        inputField.value = "";
        typingIndicator.style.display = "block";
        messageContainer.scrollTop = messageContainer.scrollHeight;

        fetch("/ai_chatbot/ask", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ question })
        })
        .then(r => r.json())
        .then(data => {
            typingIndicator.style.display = "none";
            const botMsg = document.createElement("div");
            botMsg.textContent = data?.result?.answer || "❌ Erro ou resposta inesperada.";
            botMsg.style.cssText = `
                margin-bottom: 10px;
                text-align: left;
                background-color: #e9ecef; /* Cinza claro para o bot */
                padding: 10px 15px;
                border-radius: 18px 18px 18px 3px;
                max-width: 85%;
                margin-right: auto;
                color: #333;
                box-shadow: 0 1px 2px rgba(0,0,0,0.1);
                word-wrap: break-word;
                font-size: 1em; /* Tamanho da fonte maior para mensagens do bot */
            `;
            messageContainer.appendChild(botMsg);
            messageContainer.scrollTop = messageContainer.scrollHeight;
        })
        .catch(err => {
            typingIndicator.style.display = "none";
            const errMsg = document.createElement("div");
            errMsg.textContent = "❌ Erro ao contactar o servidor.";
            errMsg.style.cssText = `
                margin-bottom: 10px;
                text-align: left;
                background-color: #ffebee;
                padding: 10px 15px;
                border-radius: 18px;
                max-width: 85%;
                margin-right: auto;
                color: #c62828;
                box-shadow: 0 1px 2px rgba(0,0,0,0.1);
                word-wrap: break-word;
                font-size: 1em; /* Tamanho da fonte maior para mensagens de erro */
            `;
            messageContainer.appendChild(errMsg);
            messageContainer.scrollTop = messageContainer.scrollHeight;
        });
    }

    if (toggleButton) toggleButton.addEventListener("click", toggleChatbotVisibility);
});
